"use client"

import { useState, useEffect } from "react"
import type { ChangeEvent } from "react"
import { DeckSearchControls } from "./DeckSearchControls"
import { DeckGrid } from "./DeckGrid"
import { DeckBrowserHero } from "./DeckBrowserHero"
import { FeaturedDecksCarousel } from "./FeaturedDecksCarousel"
import { DeckGameTabs } from "./DeckGameTabs"
import { CreateDeckModal } from "@/components/deck-builder/CreateDeckModal"
import { useCustomer } from "@/hooks/useCustomer"
import { customerBackendAPI } from "@/lib/api/customer-backend"
import { Plus } from "lucide-react"
import Link from "next/link"
import type { Format } from "@/types/tcg"

interface DeckFiltersType {
  games?: string[]
  format?: string
  minValue?: number
  maxValue?: number
  onlyValid?: boolean
}

interface Props {
  initialQuery?: string
  initialFilters?: DeckFiltersType
  initialSort?: string
  initialPage?: number
  initialView?: "all" | "my-decks" | "following"
}

export function DeckBrowsingPage({
  initialQuery = "",
  initialFilters = {},
  initialSort = "newest",
  initialPage = 1,
  initialView = "all",
}: Props) {
  const [query, setQuery] = useState(initialQuery)
  const [appliedQuery, setAppliedQuery] = useState(initialQuery.trim())
  const [filters, setFilters] = useState<DeckFiltersType>(initialFilters)
  const [sort, setSort] = useState(initialSort)
  const [page, setPage] = useState(initialPage)
  const [view] = useState<"all" | "my-decks" | "following">(initialView)
  const [showCreateModal, setShowCreateModal] = useState(false)
  const [decks, setDecks] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [availableFormats, setAvailableFormats] = useState<Format[]>([])
  const [formatsLoading, setFormatsLoading] = useState(false)
  const [totalPages, setTotalPages] = useState(1)
  const [totalResults, setTotalResults] = useState(0)
  const [activeGameTab, setActiveGameTab] = useState("ALL")

  const { customer, isAuthenticated } = useCustomer()

  // When game tab changes, update filters
  useEffect(() => {
    if (activeGameTab === "ALL") {
      setFilters((prev) => ({ ...prev, games: undefined }))
    } else {
      setFilters((prev) => ({ ...prev, games: [activeGameTab] }))
    }
    setPage(1)
  }, [activeGameTab])

  useEffect(() => {
    const loadFormats = async () => {
      setFormatsLoading(true)
      try {
        const formats = await customerBackendAPI.getFormats(
          activeGameTab === "ALL" ? undefined : activeGameTab
        )
        setAvailableFormats(formats)
        setFilters((prev) => {
          if (!prev.format) {
            return prev
          }

          return formats.some((format) => format.code === prev.format)
            ? prev
            : { ...prev, format: undefined }
        })
      } catch (formatError) {
        console.error("Failed to load deck formats:", formatError)
        setAvailableFormats([])
      } finally {
        setFormatsLoading(false)
      }
    }

    loadFormats()
  }, [activeGameTab])

  // Load decks when filters change
  useEffect(() => {
    const loadDecks = async () => {
      setLoading(true)
      setError(null)

      try {
        let result: any = { decks: [], pagination: null }

        if (view === "my-decks") {
          if (isAuthenticated && customer) {
            const params = new URLSearchParams()
            if (filters.games && filters.games.length > 0) {
              filters.games.forEach((game) => params.append("game", game))
            }

            const response = await fetch(
              `/api/decks/user/${customer.id}?${params}`,
              {
                method: "GET",
                credentials: "include",
                headers: { "Content-Type": "application/json" },
              }
            )

            if (response.ok) {
              const data = await response.json()
              const userDecks =
                data.success && data.data?.decks
                  ? data.data.decks
                  : Array.isArray(data.data)
                    ? data.data
                    : []
              result = { decks: userDecks, pagination: null }
            } else {
              console.error(
                "Failed to fetch user decks:",
                response.statusText
              )
              result = { decks: [], pagination: null }
            }
          }
        } else if (view === "all") {
          const params = new URLSearchParams()
          if (filters.games && filters.games.length > 0) {
            filters.games.forEach((game) => params.append("game", game))
          }
          if (appliedQuery) params.append("q", appliedQuery)
          if (filters.format) params.append("format", filters.format)
          if (sort) params.append("sort", sort)
          if (page) params.append("page", page.toString())
          params.append("limit", "18")

          const response = await fetch(`/api/decks/public?${params}`, {
            method: "GET",
            headers: { "Content-Type": "application/json" },
          })

          if (response.ok) {
            const data = await response.json()
            result =
              data.success && data.data
                ? data.data
                : {
                    decks: Array.isArray(data.data) ? data.data : [],
                    pagination: null,
                  }
          } else {
            console.error(
              "Failed to fetch public decks:",
              response.statusText
            )
            result = { decks: [], pagination: null }
          }
        } else if (view === "following") {
          result = { decks: [], pagination: null }
        }

        setDecks(result.decks || [])
        if (result.pagination) {
          setTotalPages(result.pagination.totalPages || 1)
          setTotalResults(result.pagination.total || 0)
        } else {
          setTotalPages(1)
          setTotalResults(result.decks?.length || 0)
        }
      } catch (error) {
        console.error("Failed to load decks:", error)
        setError("Failed to load decks")
        setDecks([])
      } finally {
        setLoading(false)
      }
    }

    loadDecks()
  }, [view, filters, sort, page, customer, isAuthenticated, appliedQuery])

  const handleSearch = () => {
    setPage(1)
    setAppliedQuery(query.trim())
  }

  const handleGameTabChange = (game: string) => {
    setActiveGameTab(game)
  }

  const handleFormatChange = (event: ChangeEvent<HTMLSelectElement>) => {
    const nextFormat = event.target.value || undefined
    setFilters((prev) => ({ ...prev, format: nextFormat }))
    setPage(1)
  }

  return (
    <>
      {/* Hero section */}
      <DeckBrowserHero
        query={query}
        onQueryChange={setQuery}
        onSearch={handleSearch}
      />

      {/* Featured decks carousel */}
      <FeaturedDecksCarousel />

      {/* Filter & Sort Bar */}
      <section
        data-testid="deck-filter-section"
        style={{
          padding: "0 32px 24px",
          borderBottom: "1px solid var(--border-default, #2C2A4A)",
        }}
      >
        <div style={{ maxWidth: 1280, margin: "0 auto" }}>
          {/* Game tabs */}
          <DeckGameTabs
            activeGame={activeGameTab}
            onGameChange={handleGameTabChange}
          />

          {/* Filter row */}
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: 12,
              flexWrap: "wrap",
            }}
          >
            {/* Format dropdown */}
            <select
              value={filters.format ?? ""}
              onChange={handleFormatChange}
              disabled={formatsLoading}
              style={{
                fontFamily: "var(--font-heading, Barlow, sans-serif)",
                fontSize: 13,
                fontWeight: 500,
                color: "var(--text-secondary, #B8B0D8)",
                background: "var(--bg-surface-2, #21203A)",
                border: "1px solid var(--border-default, #2C2A4A)",
                borderRadius: 10,
                padding: "8px 14px",
                minWidth: 168,
                cursor: "pointer",
                whiteSpace: "nowrap",
              }}
            >
              <option value="">
                {formatsLoading ? "Loading formats..." : "All Formats"}
              </option>
              {availableFormats.map((format) => (
                <option key={format.id} value={format.code}>
                  {format.name}
                </option>
              ))}
            </select>

            {/* Sort dropdown */}
            <DeckSearchControls
              sortBy={sort}
              onSortChange={setSort}
              resultsCount={totalResults}
              loading={loading}
            />

            <div style={{ flex: 1 }} />

            {/* Create button */}
            {isAuthenticated ? (
              <button
                onClick={() => setShowCreateModal(true)}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 8,
                  padding: "8px 16px",
                  fontSize: 13,
                  fontWeight: 600,
                  color: "#fff",
                  background: "var(--brand-primary, #8B5CF6)",
                  borderRadius: 10,
                  border: "none",
                  cursor: "pointer",
                  boxShadow: "0 2px 8px rgba(139, 92, 246, 0.25)",
                }}
              >
                <Plus style={{ width: 16, height: 16 }} />
                Create Deck
              </button>
            ) : (
              <Link
                href="/user"
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 8,
                  padding: "8px 16px",
                  fontSize: 13,
                  fontWeight: 600,
                  color: "#fff",
                  background: "var(--brand-primary, #8B5CF6)",
                  borderRadius: 10,
                  textDecoration: "none",
                  boxShadow: "0 2px 8px rgba(139, 92, 246, 0.25)",
                }}
              >
                Login to Create
              </Link>
            )}
          </div>
        </div>
      </section>

      {/* Deck Grid */}
      <section
        data-testid="deck-grid-section"
        style={{ padding: "32px 32px" }}
      >
        <div style={{ maxWidth: 1280, margin: "0 auto" }}>
          <DeckGrid
            decks={decks}
            loading={loading}
            error={error}
            view={view}
            isAuthenticated={isAuthenticated}
            onCreateDeck={() => setShowCreateModal(true)}
          />

          {/* Pagination placeholder — T02 creates proper pagination */}
          {totalPages > 1 && (
            <div
              data-testid="deck-pagination"
              style={{
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                gap: 4,
                paddingTop: 32,
              }}
            >
              <button
                disabled={page <= 1}
                onClick={() => setPage(page - 1)}
                style={{
                  fontFamily: "var(--font-heading, Barlow, sans-serif)",
                  fontSize: 13,
                  fontWeight: 500,
                  color: "var(--text-secondary, #B8B0D8)",
                  background: "transparent",
                  border: "1px solid var(--border-default, #2C2A4A)",
                  borderRadius: 6,
                  padding: "6px 16px",
                  cursor: page <= 1 ? "not-allowed" : "pointer",
                  opacity: page <= 1 ? 0.4 : 1,
                }}
              >
                Previous
              </button>
              {Array.from({ length: Math.min(totalPages, 7) }, (_, i) => i + 1).map((p) => (
                <button
                  key={p}
                  onClick={() => setPage(p)}
                  style={{
                    fontFamily: "var(--font-heading, Barlow, sans-serif)",
                    fontSize: 13,
                    fontWeight: 500,
                    color: p === page ? "#fff" : "var(--text-secondary, #B8B0D8)",
                    background: p === page ? "var(--brand-primary, #8B5CF6)" : "transparent",
                    border: `1px solid ${p === page ? "var(--brand-primary, #8B5CF6)" : "var(--border-default, #2C2A4A)"}`,
                    borderRadius: 6,
                    padding: "6px 12px",
                    minWidth: 36,
                    cursor: "pointer",
                  }}
                >
                  {p}
                </button>
              ))}
              <button
                disabled={page >= totalPages}
                onClick={() => setPage(page + 1)}
                style={{
                  fontFamily: "var(--font-heading, Barlow, sans-serif)",
                  fontSize: 13,
                  fontWeight: 500,
                  color: "var(--text-secondary, #B8B0D8)",
                  background: "transparent",
                  border: "1px solid var(--border-default, #2C2A4A)",
                  borderRadius: 6,
                  padding: "6px 16px",
                  cursor: page >= totalPages ? "not-allowed" : "pointer",
                  opacity: page >= totalPages ? 0.4 : 1,
                }}
              >
                Next
              </button>
            </div>
          )}
        </div>
      </section>

      {/* Community Stats Banner — placeholder */}
      <section
        data-testid="community-stats-banner"
        style={{ padding: "0 32px 40px" }}
      >
        <div
          style={{
            maxWidth: 1280,
            margin: "0 auto",
            background: "var(--bg-surface-1, #18162A)",
            border: "1px solid var(--border-default, #2C2A4A)",
            borderRadius: 20,
            padding: "32px 40px",
            display: "grid",
            gridTemplateColumns: "repeat(4, 1fr)",
            gap: 24,
            textAlign: "center",
          }}
        >
          {[
            { number: "12,847", label: "Decks Built" },
            { number: "3,421", label: "Active Brewers" },
            { number: "847K", label: "Cards Indexed" },
            { number: "4", label: "Games Supported" },
          ].map((stat) => (
            <div key={stat.label}>
              <div
                style={{
                  fontFamily: "var(--font-mono, 'DM Mono', monospace)",
                  fontSize: 28,
                  fontWeight: 500,
                  color: "var(--brand-primary, #8B5CF6)",
                  marginBottom: 4,
                }}
              >
                {stat.number}
              </div>
              <div
                style={{
                  fontSize: 13,
                  color: "var(--text-secondary, #B8B0D8)",
                }}
              >
                {stat.label}
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Mobile styles */}
      <style>{`
        @media (max-width: 640px) {
          [data-testid="deck-filter-section"] {
            padding: 0 16px 16px !important;
          }
          [data-testid="deck-grid-section"] {
            padding: 20px 16px !important;
          }
          [data-testid="community-stats-banner"] {
            padding: 0 16px 24px !important;
          }
          [data-testid="community-stats-banner"] > div {
            grid-template-columns: repeat(2, 1fr) !important;
            gap: 16px !important;
            padding: 20px !important;
          }
        }
      `}</style>

      {/* Create Deck Modal */}
      <CreateDeckModal
        isOpen={showCreateModal}
        onClose={() => setShowCreateModal(false)}
        onCreated={(newDeck) => {
          setShowCreateModal(false)
          window.location.href = `/decks/${newDeck.id}/edit`
        }}
      />
    </>
  )
}

"use client"

import { Search } from "lucide-react"

interface Props {
  query: string
  onQueryChange: (q: string) => void
  onSearch: () => void
}

export function DeckBrowserHero({ query, onQueryChange, onSearch }: Props) {
  return (
    <section
      data-testid="deck-browser-hero"
      style={{
        position: "relative",
        padding: "48px 32px 40px",
        textAlign: "center",
        background:
          "radial-gradient(ellipse 60% 100% at 50% 0%, rgba(139, 92, 246, 0.12) 0%, transparent 70%)",
        overflow: "hidden",
      }}
    >
      {/* Decorative glow */}
      <div
        style={{
          position: "absolute",
          top: -60,
          left: "50%",
          transform: "translateX(-50%)",
          width: 600,
          height: 300,
          background:
            "radial-gradient(ellipse, rgba(139, 92, 246, 0.15), transparent 70%)",
          pointerEvents: "none",
        }}
      />

      <h1
        style={{
          fontFamily: "var(--font-display, 'Barlow Condensed', sans-serif)",
          fontWeight: 700,
          fontSize: 40,
          letterSpacing: "-0.02em",
          color: "var(--text-primary, #F0EEFF)",
          marginBottom: 12,
          position: "relative",
        }}
      >
        Deck Discovery
      </h1>

      <p
        style={{
          fontFamily: "var(--font-body, Inter, sans-serif)",
          fontSize: 16,
          color: "var(--text-secondary, #B8B0D8)",
          maxWidth: 640,
          margin: "0 auto 28px",
          lineHeight: 1.6,
          position: "relative",
        }}
      >
        Explore tournament-winning builds, community favorites, and
        meta-defining strategies across all games
      </p>

      {/* Search bar */}
      <div
        style={{
          maxWidth: 560,
          margin: "0 auto",
          display: "flex",
          alignItems: "center",
          gap: 12,
          background: "rgba(33, 32, 58, 0.7)",
          border: "1.5px solid var(--border-default, #2C2A4A)",
          borderRadius: 14,
          padding: "14px 20px",
          position: "relative",
          cursor: "text",
        }}
        onClick={() => {
          const input = document.getElementById("deck-search-hero")
          input?.focus()
        }}
      >
        <Search
          style={{
            width: 20,
            height: 20,
            color: "var(--text-tertiary, #7B72A8)",
            flexShrink: 0,
          }}
        />
        <input
          id="deck-search-hero"
          type="text"
          placeholder="Search decks by name, archetype, or cards..."
          value={query}
          onChange={(e) => onQueryChange(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && onSearch()}
          style={{
            flex: 1,
            background: "transparent",
            border: "none",
            outline: "none",
            fontSize: 15,
            color: "var(--text-primary, #F0EEFF)",
            fontFamily: "var(--font-body, Inter, sans-serif)",
          }}
        />
        <span
          style={{
            marginLeft: "auto",
            fontFamily: "var(--font-mono, 'DM Mono', monospace)",
            fontSize: 11,
            color: "var(--text-tertiary, #7B72A8)",
            background: "var(--bg-surface-3, #2C2A4A)",
            padding: "3px 8px",
            borderRadius: 6,
            border: "1px solid var(--border-default, #2C2A4A)",
            flexShrink: 0,
          }}
        >
          Ctrl K
        </span>
      </div>

      {/* Mobile-specific sizing */}
      <style>{`
        @media (max-width: 640px) {
          [data-testid="deck-browser-hero"] {
            padding: 36px 20px 28px !important;
          }
          [data-testid="deck-browser-hero"] h1 {
            font-size: 28px !important;
          }
          [data-testid="deck-browser-hero"] p {
            font-size: 13px !important;
            margin-bottom: 20px !important;
          }
          [data-testid="deck-browser-hero"] > div:last-of-type {
            padding: 10px 14px !important;
            border-radius: 10px !important;
          }
          [data-testid="deck-browser-hero"] .kbd-hint {
            display: none !important;
          }
        }
      `}</style>
    </section>
  )
}

"use client"

import { useRef } from "react"
import { ChevronLeft, ChevronRight, Heart, Eye, Copy, Star } from "lucide-react"
import Link from "next/link"

const GAME_GRADIENTS: Record<string, string> = {
  MTG: "linear-gradient(135deg, rgba(167, 139, 250, 0.2), rgba(139, 92, 246, 0.08))",
  POKEMON: "linear-gradient(135deg, rgba(252, 211, 77, 0.2), rgba(251, 191, 36, 0.08))",
  YGO: "linear-gradient(135deg, rgba(96, 165, 250, 0.2), rgba(59, 130, 246, 0.08))",
  ONE_PIECE: "linear-gradient(135deg, rgba(52, 211, 153, 0.2), rgba(16, 185, 129, 0.08))",
}

const GAME_CARD_COLORS: Record<string, string> = {
  MTG: "linear-gradient(135deg, #6D28D9, #A78BFA)",
  POKEMON: "linear-gradient(135deg, #D97706, #FCD34D)",
  YGO: "linear-gradient(135deg, #1D4ED8, #60A5FA)",
  ONE_PIECE: "linear-gradient(135deg, #047857, #34D399)",
}

const GAME_BADGE_STYLES: Record<string, { bg: string; color: string }> = {
  MTG: { bg: "var(--game-mtg, #A78BFA)", color: "#1a1a2e" },
  POKEMON: { bg: "var(--game-pokemon, #FCD34D)", color: "#1a1a2e" },
  YGO: { bg: "var(--game-ygo, #60A5FA)", color: "#1a1a2e" },
  ONE_PIECE: { bg: "var(--game-op, #34D399)", color: "#1a1a2e" },
}

const GAME_LABELS: Record<string, string> = {
  MTG: "MTG",
  POKEMON: "Pokémon",
  YGO: "Yu-Gi-Oh!",
  ONE_PIECE: "One Piece",
}

interface FeaturedDeck {
  id: string
  name: string
  game: string
  format: string
  author: string
  verified: boolean
  achievement: string
  cardCount: number
  price: number
  likes: number
  copies: number
  views: string
}

export const FEATURED_DECKS_PLACEHOLDER: FeaturedDeck[] = [
  {
    id: "featured-1",
    name: "Mono Red Burn",
    game: "MTG",
    format: "Modern",
    author: "@pyromancer99",
    verified: true,
    achievement: "Top 8 at GP Chicago",
    cardCount: 60,
    price: 127,
    likes: 342,
    copies: 89,
    views: "1.2k",
  },
  {
    id: "featured-2",
    name: "Charizard ex Mill",
    game: "POKEMON",
    format: "Standard",
    author: "@firetype",
    verified: true,
    achievement: "Regional Champion",
    cardCount: 60,
    price: 185,
    likes: 456,
    copies: 124,
    views: "2.1k",
  },
  {
    id: "featured-3",
    name: "Blue-Eyes Chaos MAX",
    game: "YGO",
    format: "Advanced",
    author: "@kaibacorp",
    verified: true,
    achievement: "YCS Top 32",
    cardCount: 40,
    price: 78,
    likes: 567,
    copies: 201,
    views: "3.4k",
  },
]

interface Props {
  decks?: FeaturedDeck[]
}

export function FeaturedDecksCarousel({
  decks = FEATURED_DECKS_PLACEHOLDER,
}: Props) {
  const trackRef = useRef<HTMLDivElement>(null)

  const scroll = (dir: "left" | "right") => {
    if (!trackRef.current) return
    const amount = dir === "left" ? -504 : 504
    trackRef.current.scrollBy({ left: amount, behavior: "smooth" })
  }

  return (
    <section
      data-testid="featured-decks-carousel"
      style={{ padding: "0 32px 40px" }}
    >
      <div style={{ maxWidth: 1280, margin: "0 auto" }}>
        {/* Section header */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 10,
            marginBottom: 20,
          }}
        >
          <Star
            style={{
              width: 20,
              height: 20,
              color: "var(--brand-secondary, #FF7849)",
              fill: "var(--brand-secondary, #FF7849)",
            }}
          />
          <span
            style={{
              fontFamily: "var(--font-heading, Barlow, sans-serif)",
              fontWeight: 600,
              fontSize: 18,
              color: "var(--text-primary, #F0EEFF)",
            }}
          >
            Featured This Week
          </span>
        </div>

        {/* Carousel */}
        <div style={{ position: "relative" }}>
          {/* Left arrow */}
          <button
            onClick={() => scroll("left")}
            aria-label="Scroll featured decks left"
            style={{
              position: "absolute",
              top: "50%",
              left: -20,
              transform: "translateY(-50%)",
              width: 40,
              height: 40,
              borderRadius: "50%",
              background: "rgba(24, 22, 42, 0.9)",
              border: "1px solid var(--border-default, #2C2A4A)",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              zIndex: 10,
              cursor: "pointer",
            }}
          >
            <ChevronLeft
              style={{
                width: 16,
                height: 16,
                color: "var(--text-secondary, #B8B0D8)",
              }}
            />
          </button>

          {/* Track */}
          <div
            ref={trackRef}
            style={{
              display: "flex",
              gap: 24,
              overflow: "hidden",
              scrollSnapType: "x mandatory",
            }}
          >
