const GAME_COLORS: Record<string, string> = {
  ALL: "var(--brand-primary, #8B5CF6)",
  MTG: "var(--game-mtg, #A78BFA)",
  POKEMON: "var(--game-pokemon, #FCD34D)",
  YUGIOH: "var(--game-ygo, #60A5FA)",
  OPTCG: "var(--game-op, #34D399)",
}

const GAME_TAB_ITEMS = [
  { code: "ALL", label: "All" },
  { code: "MTG", label: "MTG" },
  { code: "POKEMON", label: "Pokémon" },
  { code: "YUGIOH", label: "Yu-Gi-Oh!" },
  { code: "OPTCG", label: "One Piece" },
]

interface Props {
  activeGame: string
  onGameChange: (game: string) => void
}

export function DeckGameTabs({ activeGame, onGameChange }: Props) {
  return (
    <div
      data-testid="deck-game-tabs"
      style={{
        display: "flex",
        alignItems: "center",
        gap: 0,
        marginBottom: 16,
        borderBottom: "1px solid var(--border-default, #2C2A4A)",
        overflowX: "auto",
        WebkitOverflowScrolling: "touch",
      }}
    >
      {GAME_TAB_ITEMS.map((item) => {
        const isActive = activeGame === item.code
        const gameColor = GAME_COLORS[item.code]

        return (
          <button
            key={item.code}
            data-testid={`deck-game-tab-${item.code}`}
            onClick={() => onGameChange(item.code)}
            style={{
              fontFamily: "var(--font-heading, Barlow, sans-serif)",
              fontSize: 14,
              fontWeight: 600,
              color: isActive ? gameColor : "var(--text-tertiary, #7B72A8)",
              padding: "12px 20px",
              borderBottom: `2px solid ${isActive ? gameColor : "transparent"}`,
              cursor: "pointer",
              transition: "color 0.15s",
              whiteSpace: "nowrap",
              background: "transparent",
              border: "none",
              borderBottomWidth: 2,
              borderBottomStyle: "solid",
              borderBottomColor: isActive ? gameColor : "transparent",
            }}
          >
            {item.label}
          </button>
        )
      })}
    </div>
  )
}

